// Extract clean email data. Runs once for each item.
const item = $input.item;

function extractEmail(str) {
  if (!str) return '';
  const match = str.match(/<([^>]+)>/) || str.match(/([^\s]+@[^\s]+)/);
  return match ? match[1] : str.trim();
}

const emailData = item.json.rawEmail?.rawEmail ? item.json.rawEmail : item.json;
const from = extractEmail(emailData.from);
const to = extractEmail(emailData.to);
const subject = emailData.subject || '';
const textBody = emailData.textPlain || emailData.textBody || '';
const htmlBody = emailData.textHtml || emailData.htmlBody || '';
const rawDate = emailData.date || emailData.receivedDate || emailData.sentDate || emailData.createdAt;
const parsedDate = rawDate ? new Date(rawDate) : null;

if (!parsedDate || Number.isNaN(parsedDate.getTime())) {
  throw new Error(`E-mail heeft geen geldige brondatum: ${subject || emailData.metadata?.['message-id'] || 'onbekend bericht'}`);
}

const receivedDate = parsedDate.toISOString();
const messageId = emailData.metadata?.['message-id'] || emailData.messageId || '';
const body = textBody || htmlBody.replace(/<[^>]*>/g, ' ').replace(/\s+/g, ' ').trim();
const clientEmail = from.includes('@devreemakelaardij.nl') ? to : from;

return {
  json: {
    emailId: messageId,
    from,
    to,
    clientEmail,
    subject,
    textBody: body,
    receivedDate,
    rawEmail: emailData
  }
};

// Helper function to extract email from string like "Name <email@domain.com>"
function extractEmail(str) {
  if (!str) return '';
  const match = str.match(/<([^>]+)>/) || str.match(/([^\s]+@[^\s]+)/);
  return match ? match[1] : str.trim();
}

const from = extractEmail($json.from);
const to = extractEmail($json.to);
const subject = $json.subject || '';

const isInternal = from.includes('devreemakelaardij.nl') && to.includes('devreemakelaardij.nl');

// Check if from/to contains system addresses
const systemPrefixes = ['no-reply', 'noreply', 'do-not-reply', 'mailer', 'postmaster'];
const isSystem = systemPrefixes.some(prefix => from.includes(prefix) || to.includes(prefix));

// Check if from/to contains business platforms
const businessDomains = ['move.nl', 'funda.nl', 'realworks.nl', 'nvm.nl', 'pararius.nl', 'voys.nl', 'eu.sparkpostmail1.com', 'nazca4u.nl', 'eneco.com', 'nwwi.nl', 'mailing.nwwi.nl', 'mrvo.nl'];
const isBusiness = businessDomains.some(domain => from.includes(domain) || to.includes(domain));

// Check if subject contains system keywords
const systemKeywords = ['Out of Office', 'Automatic Reply', 'Delivery Status', 'Mail Delivery Failed', 'Undeliverable'];
const isSystemSubject = systemKeywords.some(keyword => subject.includes(keyword));

// Block if any condition is true
const shouldBlock = isInternal || isSystem || isBusiness || isSystemSubject;

if (shouldBlock) {
  console.log('‚ùå Blocked:', from, '‚Üí', to, '|', subject);
  return null; // Return null om item te blokkeren
}

console.log('‚úÖ Allowed:', from, '‚Üí', to, '|', subject);
return { json: $json }; // Return enkel object (geen array!)
